B.Ou=new A.F(B.k,[u.s,"Mitgr\xfcnder & Lead Developer \u2013 Multiplayer-Kartenspiel"],t.w)
B.OK=new A.F(B.k,[u.K,"Gaming-Startup, Dortmund, Deutschland. Plattform\xfcbergreifendes Kartenspiel mit eigener Rendering-Engine und skalierbarem Serverless-Backend."],t.w)
B.Pa=new A.F(B.k,[u.x,"Ich habe eine performante, plattform\xfcbergreifende Kartenspiel-Engine entwickelt, indem ich das Flutter-Framework um eigene Rendering-Logik erweitert habe \u2013 mit 60 FPS auf Android, iOS, Web, Windows, macOS und Linux."],t.w)
B.OJ=new A.F(B.k,[u.F,"Ich habe ein skalierbares Serverless-Backend mit Firebase Cloud Functions und NoSQL (Firestore) konzipiert, das Echtzeit-Spielzust\xe4nde und persistente Nutzerdaten f\xfcr eine potenziell globale Spielerbasis verwaltet."],t.w)
B.Pq=new A.F(B.k,["Sept 2019 - Oct 2019","Sep. 2019 \u2013 Okt. 2019"],t.w)
B.O1=new A.F(B.k,[u.aT,"Praktikant in Maschinen- und Elektrotechnik \u2013 IMA Schelling GmbH"],t.w)
B.NC=new A.F(B.k,[u.J,"W\xe4hrend meines achtw\xf6chigen Grundpraktikums bei der IMA Schelling GmbH in den Bereichen Maschinenbau und Elektrotechnik hatte ich die Gelegenheit, an verschiedenen Aufgaben zu arbeiten."],t.w)
B.OF=new A.F(B.k,[u.aD,"Dazu geh\xf6rte die Entwicklung und Optimierung elektrischer Steuerungen mit TwinCAT."],t.w)
B.OW=new A.F(B.k,[u.a3,"Ich war an Montage, Installation, Pr\xfcfung, Inspektion und Wartung pneumatischer Systeme beteiligt."],t.w)
B.NX=new A.F(B.k,[u.X,"Zus\xe4tzlich habe ich praktische Erfahrung in der Fertigung verschiedener metallischer Bauteile mit unterschiedlichen Produktionsverfahren gesammelt \u2013 mit Handwerkzeugen sowie an Dreh- und Fr\xe4smaschinen."],t.w)
B.Pt=new A.F(B.k,["Since 2020","Seit 2020"],t.w)
B.NQ=new A.F(B.k,[u.bE,"IU Internationale Hochschule (Fernstudium)"],t.w)
B.Po=new A.F(B.k,["Degree Program: Psychology (B.Sc.)","Studiengang: Psychologie (B.Sc.)"],t.w)
B.Pl=new A.F(B.k,["Since Oct 2018","Seit Okt. 2018"],t.w)
B.OE=new A.F(B.k,["Technical University in Dortmund","Technische Universit\xe4t Dortmund"],t.w)
B.Pe=new A.F(B.k,[u.A,"Studiengang: Wirtschaftsingenieurwesen (B.Sc.)\nProfil: Management elektrischer Systeme"],t.w)
B.Ot=new A.F(B.k,[u.g,"Workshop zu 3D-Druck und Laser-Holzschneider"],t.w)
B.Nv=new A.F(B.k,["Programming of a Micro Controller ","Programmierung eines Mikrocontrollers "],t.w)
B.NR=new A.F(B.k,[u.Y,"Analyse und Modifikation von Signalen mit einem Oszilloskop"],t.w)
B.NB=new A.F(B.k,["Programming a Turtlebot with ROS in C++","Programmierung eines Turtlebots mit ROS in C++"],t.w)
B.Ps=new A.F(B.k,[u.aP,"Ich habe eine wissenschaftliche Arbeit zur Anwendung und Optimierung von Objekterkennung bei Nacht mittels Deep Learning (YOLOv8) in einer simulierten urbanen Umgebung aus der Perspektive eines fahrenden Autos verfasst."],t.w)
B.NW=new A.F(B.k,[u.q,'Aktuell arbeite ich an meiner Bachelorarbeit mit dem Titel:\n\u201eEvaluation des Einflusses von Beleuchtungs- und Trainingsparametern auf die Objekterkennung durch k\xfcnstliche neuronale Netze bei virtuellen Nachtfahrten.".'],t.w)
